UPDATE clinlims.lab_roles
SET role = (SELECT id FROM clinlims.system_role WHERE name = 'Results')
WHERE role = (SELECT id FROM clinlims.system_role WHERE name = 'Results entry')
  AND NOT EXISTS (
      SELECT 1 FROM clinlims.lab_roles x
      WHERE x.lab_unit_role_map_id = clinlims.lab_roles.lab_unit_role_map_id
        AND x.role = (SELECT id FROM clinlims.system_role WHERE name = 'Results')
  );

DELETE FROM clinlims.lab_roles
WHERE role = (SELECT id FROM clinlims.system_role WHERE name = 'Results entry');

UPDATE clinlims.lab_roles
SET role = (SELECT id FROM clinlims.system_role WHERE name = 'Validation')
WHERE role = (SELECT id FROM clinlims.system_role WHERE name = 'Validator')
  AND NOT EXISTS (
      SELECT 1 FROM clinlims.lab_roles x
      WHERE x.lab_unit_role_map_id = clinlims.lab_roles.lab_unit_role_map_id
        AND x.role = (SELECT id FROM clinlims.system_role WHERE name = 'Validation')
  );

DELETE FROM clinlims.lab_roles
WHERE role = (SELECT id FROM clinlims.system_role WHERE name = 'Validator');
